"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["31758"],{10279(e){e.exports=JSON.parse('{"tag":{"label":"Durable Execution","permalink":"/tags/durable-execution","allTagsPath":"/tags","count":12,"items":[{"id":"encyclopedia/temporal-sdks","title":"About Temporal SDKs","description":"Temporal SDKs are open-source tools enabling scalable and reliable application development. They feature APIs for Workflow and Activity execution, automatic retries, and resilience mechanisms, making it easier to build fault-tolerant applications.","permalink":"/encyclopedia/temporal-sdks"},{"id":"encyclopedia/activities/activity-definition","title":"Activity Definition","description":"Learn about defining Temporal Activities, including Activity Types, parameters, and implementation details.","permalink":"/activity-definition"},{"id":"encyclopedia/activities/activity-execution","title":"Activity Execution","description":"Understand how Activity Executions work in Temporal, including retries, timeouts, and failure handling.","permalink":"/activity-execution"},{"id":"encyclopedia/activities/local-activity","title":"Local Activity","description":"Learn about Local Activities in Temporal, their benefits, execution model, and when to use them.","permalink":"/local-activity"},{"id":"encyclopedia/activities/standalone-activity","title":"Standalone Activity","description":"Learn about Standalone Activities in Temporal, their benefits, execution model, and when to use them.","permalink":"/standalone-activity"},{"id":"production-deployment/self-hosted-guide/checklist","title":"Temporal Platform\'s production readiness checklist","description":"Optimize your Temporal Service for production with scaling, metrics, load testing, and effective workflow versioning techniques. Ensure robust performance and future-proof your workflows.","permalink":"/self-hosted-guide/production-checklist"},{"id":"production-deployment/worker-deployments/kubernetes-controller","title":"Temporal Worker Controller","description":"Use Temporal\'s provided Kubernetes controller to programmatically scale your Worker deployments.","permalink":"/production-deployment/worker-deployments/kubernetes-controller"},{"id":"production-deployment/worker-deployments/index","title":"Temporal Worker deployments","description":"Programmatically scale and deploy your Temporal Workers into common production environments using our provided tooling and best practices.","permalink":"/production-deployment/worker-deployments"},{"id":"encyclopedia/activities/activities","title":"What is a Temporal Activity?","description":"Understand Temporal Activities, including  Activity Definitions, Types, Executions, idempotency, cancellations, Local Activities, and Standalone Activities.","permalink":"/activities"},{"id":"encyclopedia/temporal","title":"What is Temporal?","description":"Temporal is a scalable platform that ensures the Durable Execution of application code, allowing reliable and resilient Workflow Executions even in the face of failures like network outages or server crashes.","permalink":"/temporal"},{"id":"evaluate/why-temporal","title":"Why Temporal?","description":"Temporal enhances Workflow reliability, productivity, and state visibility for developers by offering Durable Execution, simplified code structures, and robust monitoring tools.","permalink":"/evaluate/why-temporal"},{"id":"production-deployment/worker-deployments/worker-versioning","title":"Worker Versioning","description":"Use Worker Versioning to pin Workflow revisions to individual Worker Deployment Versions, avoiding the need for patching to support multiple code paths.","permalink":"/production-deployment/worker-deployments/worker-versioning"}],"unlisted":false}}')}}]);